	"k8s.io/apimachinery/pkg/util/sets"
	endpointutil "k8s.io/endpointslice/util"
	"k8s.io/klog/v2"
	utilnet "k8s.io/utils/net"
	"k8s.io/utils/ptr"
)

// hasTaintEffectNoScheduleNoTraffic checks if a node has an untolerated NoScheduleNoTraffic taint for a given pod.
func hasTaintEffectNoScheduleNoTraffic(pod *v1.Pod, node *v1.Node) bool {
	if node == nil {
		return false
	}

	for _, taint := range node.Spec.Taints {
		if taint.Effect != v1.TaintEffectNoScheduleNoTraffic {
			continue
		}

		// Check if the pod tolerates this taint
		tolerates := false
		for _, toleration := range pod.Spec.Tolerations {
			if toleration.ToleratesTaint(&taint) {
				tolerates = true
				break
			}
		}

		if !tolerates {
			return true
		}
	}

	return false
}

// podToEndpoint returns an Endpoint object generated from a Pod, a Node, and a Service for a particular addressType.
func podToEndpoint(pod *v1.Pod, node *v1.Node, service *v1.Service, addressType discovery.AddressType) discovery.Endpoint {
	serving := endpointutil.IsPodReady(pod)
	terminating := pod.DeletionTimestamp != nil
	// For compatibility reasons, "ready" should never be "true" if a pod is terminatng, unless
	// publishNotReadyAddresses was set.
	ready := (service.Spec.PublishNotReadyAddresses || (serving && !terminating)) && !hasTaintEffectNoScheduleNoTraffic(pod, node)
	ep := discovery.Endpoint{
		Addresses: getEndpointAddresses(pod.Status, service, addressType),
		Conditions: discovery.EndpointConditions{
			Ready:       &ready,
			Serving:     &serving,
			Terminating: &terminating,
		},
